const items = $input.all();
const results = items[0]?.json?.results || [];

const now = new Date();
const today = now.toISOString().split('T')[0];

const stages = {};
let totalValue = 0;
const atRisk = [];

for (const deal of results) {
  const props = deal.properties;
  const stage = props.dealstage || 'unknown';
  const amount = parseFloat(props.amount) || 0;
  totalValue += amount;

  if (!stages[stage]) stages[stage] = { count: 0, value: 0 };
  stages[stage].count++;
  stages[stage].value += amount;

  const lastMod = new Date(props.hs_lastmodifieddate);
  const daysSince = Math.floor((now - lastMod) / (1000 * 60 * 60 * 24));
  if (daysSince > 7) {
    atRisk.push(`• ${props.dealname || 'Unnamed'} (${daysSince}d stale)`);
  }
}

const stageLines = Object.entries(stages)
  .map(([s, d]) => `• ${s}: ${d.count} deal${d.count !== 1 ? 's' : ''} — $${d.value.toLocaleString()}`)
  .join('\n');

return [{
  json: {
    total_deals: results.length,
    total_value: totalValue.toLocaleString(),
    at_risk_count: atRisk.length,
    stage_summary: stageLines || '• No active deals',
    at_risk_summary: atRisk.slice(0, 5).join('\n') || '• None — all deals active',
    date: today
  }
}];

